   112	    if (charging) {
   113	      if (percentage <= 10)
   114	        return "󰂄";
   115	      if (percentage <= 25)
   116	        return "󰂆";
   117	      if (percentage <= 35)
   118	        return "󰂇";
   119	      if (percentage <= 45)
