   341	  function refreshBluetoothSelectorDevices(scan, silent = false) {
   342	    if (bluetoothSelectorProcess.running)
   343	      return;
   344	    bluetoothSelectorRefreshSilent = silent;
   345	    if (!silent) {
   346	      bluetoothSelectorLoading = true;
