   352	    bluetoothSelectorProcess.running = true;
   353	  }
   354	
   355	  function activateSelectedBluetoothDevice() {
   356	    if (bluetoothActionProcess.running)
   357	      return;
   358	    const devices = currentBluetoothDevices();
   359	    if (devices.length === 0)
   360	      return;
   361	    const device = devices[Math.min(bluetoothSelectedIndex, devices.length - 1)];
   362	    const connectedNow = Bluetooth.devices.values.some(candidate =>
   363	      candidate.address === device.address && candidate.connected);
   364	    bluetoothAction = bluetoothTab === 1
   365	      ? "pair" : connectedNow ? "disconnect" : "connect";
   366	    bluetoothSelectorMessage = bluetoothAction === "pair"
   367	      ? "Pairing with " + device.name + "…"
   368	      : bluetoothAction === "connect"
   369	        ? "Connecting to " + device.name + "…"
   370	        : "Disconnecting " + device.name + "…";
   371	    bluetoothActionProcess.exec(["bluetoothctl", "--timeout", "20",
   372	      bluetoothAction, device.address]);
   373	  }
   374	
   375	  function finishBluetoothAction(output) {
   376	    const result = output.toLowerCase();
   377	    const failed = result.includes("failed") || result.includes("not available")
   378	      || result.includes("error");
   379	    const succeeded = !failed && (result.includes("successful")
   380	      || result.includes("successfully"));
   381	
   382	    if (succeeded) {
   383	      if (bluetoothAction === "pair") {
