   412	        return;
   413	      }
   414	      wifiPendingNetwork = network;
   415	      wifiMessage = "Connecting to " + network.ssid + "…";
   416	      wifiPasswordConnectProcess.command = ["bash",
   417	        Quickshell.shellDir + "/scripts/wifi-connect-password.sh", network.ssid];
   418	      wifiPasswordConnectProcess.running = true;
