   490	      nixForceProcess.running = true;
   491	    }
   492	  }
   493	
   494	  function parseNixStatus(text) {
   495	    try {
   496	      const status = JSON.parse(text.trim());
   497	      if (Array.isArray(status.updates)) {
   498	        root.nixUpdates = status.updates;
   499	        root.nixIcon = status.hasUpdates ? "" : "";
   500	        root.nixTooltip = status.hasUpdates
   501	          ? status.updates.map(update => update.name + ": " + update.date).join("\n")
   502	          : status.message || "System is up to date";
   503	      } else {
   504	        // Compatibility with the preserved Waybar helper cache format.
   505	        root.nixIcon = status.alt === "has-updates" ? "" : "";
   506	        root.nixTooltip = status.tooltip || "System is up to date";
   507	        const lines = status.alt === "has-updates"
   508	          ? root.nixTooltip.split("\n").filter(line => line.trim() !== "") : [];
   509	        root.nixUpdates = lines.map(line => {
   510	          const separator = line.lastIndexOf(": ");
   511	          return separator >= 0
   512	            ? { "name": line.slice(0, separator), "date": line.slice(separator + 2) }
   513	            : { "name": line, "date": "" };
   514	        });
   515	      }
   516	    } catch (error) {
   517	      root.nixUpdates = [];
   518	      root.nixTooltip = "Unable to check for updates";
   519	    }
   520	    root.nixChecking = false;
   521	  }
