   359	    # ───── 1. THE CHECKER SCRIPT (Smart Wrapper) ─────
   360	    (writeShellScriptBin "nixos-update-checker" ''
   361	      #!/usr/bin/env bash
   362	      set -uo pipefail
   363	
   364	      CACHE_FILE="/tmp/nixos-update-status.json"
   365	      FLAKE_DIR="$HOME/.config/nixos"
   366	
   367	      # 1. The Heavy Check Function
   368	      do_check() {
   369	        # Create temp directory to avoid locking the real flake
   370	        TMP_DIR=$(mktemp -d)
   371	        trap 'rm -rf "$TMP_DIR"' EXIT
   372	
   373	        cp "$FLAKE_DIR/flake.nix" "$TMP_DIR/"
   374	        cp "$FLAKE_DIR/flake.lock" "$TMP_DIR/" 2>/dev/null || true
   375	
   376	        # Run the update in dry-run mode
   377	        update_output=$(nix flake update --flake "$TMP_DIR" 2>&1 || echo "Error checking")
   378	
   379	        # Parse the output using your original AWK logic
   380	        updates=$(echo "$update_output" | awk '
   381	          /Updated input/ {
   382	              # Match name inside single quotes
   383	              match($0, /\x27[^\x27]+\x27/);
   384	              if (RSTART > 0) {
   385	                name = substr($0, RSTART+1, RLENGTH-2);
   386	              }
   387	          }
   388	          /→/ {
   389	              # Match date inside parentheses (YYYY-MM-DD)
   390	              match($0, /\([0-9]{4}-[0-9]{2}-[0-9]{2}\)/);
   391	              if (RSTART > 0) {
   392	                date = substr($0, RSTART+1, RLENGTH-2);
   393	              } else {
   394	                date = "unknown";
   395	              }
   396	              # Print "nixpkgs: 2026-02-09"
   397	              print name ": " date;
   398	          }
   399	        ')
   400	
   401	        # Count how many updates found
   402	        count=$(echo -n "$updates" | grep -c '^' || true)
   403	
   404	        if [[ -n "$updates" && "$count" -gt 0 ]]; then
   405	          # Safely escape the list for JSON (requires jq)
   406	          tooltip_esc=$(printf '%s' "$updates" | jq -R -s '.')
   407	
   408	          # Write JSON: icon is "has-updates", tooltip has the list
   409	          printf '{"text":"","alt":"has-updates","class":"has-updates","tooltip":%s}\n' "$tooltip_esc" > "$CACHE_FILE"
   410	        else
   411	          # Write JSON: icon is "updated", tooltip is simple text
   412	          printf '{"text":"","alt":"updated","class":"updated","tooltip":"System is up to date"}\n' > "$CACHE_FILE"
   413	        fi
   414	      }
   415	
   416	      # 2. Logic Controller
   417	
   418	      # A) Force check (Right Click)
   419	      if [[ "''${1:-}" == "force" ]]; then
   420	        do_check
   421	        cat "$CACHE_FILE"
   422	        exit 0
   423	      fi
   424	
   425	      # B) Interval Check (Every 30m)
   426	      current_time=$(date +%s)
   427	      if [[ -f "$CACHE_FILE" ]]; then
   428	        file_time=$(stat -c %Y "$CACHE_FILE")
   429	        age=$((current_time - file_time))
   430	      else
   431	        age=99999
   432	      fi
   433	
   434	      # Only run check if cache is older than 30 mins (1800s)
   435	      if [[ $age -ge 1800 ]]; then
   436	        do_check
   437	      fi
   438	
   439	      # C) Always print the result for Waybar
   440	      if [[ -f "$CACHE_FILE" ]]; then
   441	        cat "$CACHE_FILE"
   442	      else
   443	        # Fallback if first run hasn't finished
   444	        echo '{"text":"","alt":"updated","class":"updated","tooltip":"Checking..."}'
   445	      fi
   446	    '')
