   404	        if [[ -n "$updates" && "$count" -gt 0 ]]; then
   405	          # Safely escape the list for JSON (requires jq)
   406	          tooltip_esc=$(printf '%s' "$updates" | jq -R -s '.')
   407	
   408	          # Write JSON: icon is "has-updates", tooltip has the list
   409	          printf '{"text":"","alt":"has-updates","class":"has-updates","tooltip":%s}\n' "$tooltip_esc" > "$CACHE_FILE"
   410	        else
   411	          # Write JSON: icon is "updated", tooltip is simple text
   412	          printf '{"text":"","alt":"updated","class":"updated","tooltip":"System is up to date"}\n' > "$CACHE_FILE"
   413	        fi
   414	      }
   415	
   416	      # 2. Logic Controller
   417	
   418	      # A) Force check (Right Click)
   419	      if [[ "''${1:-}" == "force" ]]; then
   420	        do_check
   421	        cat "$CACHE_FILE"
   422	        exit 0
   423	      fi
   424	
   425	      # B) Interval Check (Every 30m)
   426	      current_time=$(date +%s)
   427	      if [[ -f "$CACHE_FILE" ]]; then
   428	        file_time=$(stat -c %Y "$CACHE_FILE")
   429	        age=$((current_time - file_time))
   430	      else
   431	        age=99999
   432	      fi
   433	
   434	      # Only run check if cache is older than 30 mins (1800s)
   435	      if [[ $age -ge 1800 ]]; then
   436	        do_check
   437	      fi
   438	
   439	      # C) Always print the result for Waybar
   440	      if [[ -f "$CACHE_FILE" ]]; then
   441	        cat "$CACHE_FILE"
   442	      else
   443	        # Fallback if first run hasn't finished
   444	        echo '{"text":"","alt":"updated","class":"updated","tooltip":"Checking..."}'
   445	      fi
   446	    '')
   447	
   448	    # ───── 2. THE BUILDER SCRIPT (Click Logic) ─────
   449	    (writeShellScriptBin "nixos-update-installer" ''
   450	      #!/usr/bin/env bash
   451	      set -e
   452	      echo "📦 Starting update..."
   453	      cd ~/.config/nixos
   454	
   455	      # Update lockfile
   456	      nix flake update
   457	
   458	      # Rebuild System (using nh or nixos-rebuild)
   459	      if nh os switch; then
   460	        echo ""
   461	        echo "✅ Update Complete!"
   462	
   463	        # 1. Overwrite the cache with "Up to date" status
   464	        echo '{"text":"", "alt":"updated", "class":"updated", "tooltip":"Just updated"}' > /tmp/nixos-update-status.json
   465	
   466	        # 2. Ask the Quickshell top bar to refresh the update indicator.
   467	        qs --config top-bar ipc call topbar refreshNix || true
   468	
   469	        echo "Icon refreshed."
   470	        read -p "Press Enter to close..."
   471	      else
   472	        echo "❌ Update Failed."
   473	        read -p "Press Enter to inspect error..."
   474	      fi
   475	    '')
   476	    (rustPlatform.buildRustPackage {
   477	      pname = "gpu-usage-waybar";
   478	      version = "v0.1.24"; # latest release, 3 May 2025 :contentReference[oaicite:0]{index=0}
   479	
   480	      src = fetchFromGitHub {
   481	        # pulls the exact crate published to crates.io
   482	        owner = "PolpOnline";
   483	        repo = "gpu-usage-waybar";
   484	        rev = "v0.1.23";
   485	        hash = "sha256-DUIKiUgTy4jn8NZZvjC0zuA993Sbq1Fvr7tvJw3+tNw="; # first run with lib.fakeSha256, copy real hash
   486	      };
   487	
   488	      # Cargo.lock lives in the repo, so just grab the hashes once:
   489	      cargoHash = "sha256-X3Ak0K1kt7++tE7qZgy8GaRzqemUNTJ3z1yGBJZyA4s=";
   490	      doCheck = false; # upstream has no tests yet :contentReference[oaicite:1]{index=1}
   491	    })
