     1	import Quickshell
     2	import Quickshell.Hyprland
     3	import Quickshell.Wayland
     4	import QtQuick
     5	
     6	PanelWindow {
     7	  id: window
     8	
     9	  required property var modelData
    10	  required property var statusData
    11	
    12	  property bool entered: false
    13	  property var pendingTooltipAnchor: null
    14	  property var tooltipAnchor: null
    15	  property string tooltipText: ""
    16	  property string pendingTooltipText: ""
    17	  property bool tooltipVisible: false
    18	  readonly property var hyprlandMonitor: Hyprland.monitorFor(window.screen)
    19	  readonly property bool wifiSelectorActive: statusData.wifiSelectorVisible
    20	  readonly property bool bluetoothSelectorActive: statusData.bluetoothSelectorVisible
    21	  readonly property bool updateSelectorActive: statusData.updateSelectorVisible
    22	  readonly property bool wifiSelectorKeyboardActive: wifiSelectorActive
    23	    && hyprlandMonitor !== null
    24	    && hyprlandMonitor.name === statusData.wifiTargetMonitor
    25	  readonly property bool bluetoothSelectorKeyboardActive: bluetoothSelectorActive
    26	    && hyprlandMonitor !== null
    27	    && hyprlandMonitor.name === statusData.bluetoothTargetMonitor
    28	  readonly property bool updateSelectorKeyboardActive: updateSelectorActive
    29	    && hyprlandMonitor !== null
    30	    && hyprlandMonitor.name === statusData.updateTargetMonitor
    31	  readonly property bool keyboardSelectorActive: wifiSelectorKeyboardActive
    32	    || bluetoothSelectorKeyboardActive || updateSelectorKeyboardActive
    33	
    34	  screen: modelData
    35	
    36	  anchors {
    37	    top: true
    38	    left: true
    39	    right: true
    40	  }
    41	
    42	  margins {
    43	    top: 10
    44	    left: 5
    45	    right: 5
    46	  }
    47	
    48	  // Keep the layer surface geometry fixed so expanding the update card cannot
    49	  // nudge the other bar modules. The mask leaves the unused area click-through.
    50	  implicitHeight: 600
