   301	        if (distance <= arcLength) {
   302	          angle = -Math.PI / 2 + distance / radius;
   303	          return { "x": width - inset - pathRadius + Math.cos(angle) * radius,
   304	            "y": inset + pathRadius + Math.sin(angle) * radius };
