   318	        distance -= arcLength;
   319	
   320	        if (distance <= horizontalLength)
   321	          return { "x": width - inset - pathRadius - distance,
   322	            "y": height - inset };
   323	        distance -= horizontalLength;
   324	
   325	        if (distance <= arcLength) {
   326	          angle = Math.PI / 2 + distance / radius;
   327	          return { "x": inset + pathRadius + Math.cos(angle) * radius,
   328	            "y": height - inset - pathRadius + Math.sin(angle) * radius };
