arguments.command:
set -euo pipefail
for f in home_manager/hyprland/quickshell/top-bar/scripts/*.sh; do
  echo "--- smoke $f ---"
  case "$f" in
    *system-stats.sh) timeout 3 bash "$f" | head -n1 | jq -e 'has("cpu") and has("memory") and has("disk") and has("brightness") and has("networkType") and has("networkName") and has("networkStrength")' ;;
    *bluetooth-devices.sh) bash "$f" no | jq -e 'type == "array"' ;;
    *wifi-networks.sh) bash "$f" auto | jq -e 'type == "array"' ;;
    *wifi-connect-password.sh) echo 'skipped interactive network connection helper' ;;
  esac
done

